{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/AnnotationRuleOfficialTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class AnnotationRuleOfficialTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }
        .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)

    @Test
    fun `Given annotations before the class constructor should be wrapped when code style ktlint_official is used`() {
        val code =
            """
            data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            data class Foo
                @Bar1
                @Bar2("bar")
                @Bar3
                @Bar4
                constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 16, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                LintViolation(1, 35, "Annotation must be placed on a separate line when it is preceded by another annotation on a separate line"),
                LintViolation(1, 41, "Annotation must be placed on a separate line when it is preceded by another annotation on a separate line"),
                LintViolation(1, 47, "Multiple annotations should not be placed on the same line as the annotated construct"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Annotations on type projections should be wrapped in same way as other annotations`() {
        val code =
            """
            val fooBar: FooBar<String, @Foo String, @Foo @Bar String, @Bar("bar") @Foo String> = FooBar()
            """.trimIndent()
        val formattedCode =
            """
            val fooBar: FooBar<
                String,
                @Foo String,
                @Foo @Bar
                String,
                @Bar("bar")
                @Foo
                String
                > = FooBar()
            """.trimIndent()
        annotationRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .hasLintViolations(
                LintViolation(1, 39, "Expected newline after ','"),
                LintViolation(1, 51, "Multiple annotations should not be placed on the same line as the annotated construct"),
                LintViolation(1, 57, "Expected newline after ','"),
                LintViolation(1, 59, "Expected newline before '@'"),
                LintViolation(1, 59, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                LintViolation(1, 76, "Multiple annotations should not be placed on the same line as the annotated construct"),
                LintViolation(1, 82, "Expected newline before '>'"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Type argument list only contains type projections without or with a single annotation without parameter`() {
        val code =
            """
            val foo1: List<@Foo String> = emptyList()
            val foo2 = emptyList<@Foo String>()
            val foo3: Map<@Foo String, @Foo String> = emptyMap()
            val foo4 = emptyMap<@Foo String, @Foo String>()
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

