import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class AnnotationRuleOfficialTest {
    private val annotationRuleAssertThat = assertThatRule(
        { AnnotationRule() },
        additionalRuleProviders = setOf({ IndentationRule() }, { WrappingRule() }),
        editorConfigProperties = setOf(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
    )

    @Test
    fun `Given annotations before the class constructor should be wrapped when code style ktlint_official is used`() {
        val code =
            """
            data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            data class Foo
                @Bar1
                @Bar2("bar")
                @Bar3
                @Bar4
                constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 16, "Annotation must be placed on a separate line"),
                LintViolation(1, 22, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                LintViolation(1, 22, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                LintViolation(1, 22, "Annotation must be placed on a separate line"),
                LintViolation(1, 35, "Annotation must be placed on a separate line"),
                LintViolation(1, 41, "Annotation must be placed on a separate line"),
                LintViolation(1, 47, "Multiple annotations should not be placed on the same line as the annotated construct"),
            ).isFormattedAs(formattedCode)
    }
}
"}

